fixed_code:
use std::collections::HashMap;

struct Node {
    value: i32,
    next: Option<Box<Node>>
}

fn main() {
    let mut nodes = HashMap::new();
    for i in 0..5 {
        let node = Node { value: i, next: None };
        nodes.insert(i, Box::new(node));
    }
}
